schyrs_c     0.048266   0.005846   8.256 3.55e-16 ***
exper_c      0.150389   0.017666   8.513  < 2e-16 ***
exper2_c    -0.067091   0.017260  -3.887 0.000106 ***
semiwhite   -0.142749   0.032712  -4.364 1.38e-05 ***
semiblue    -0.275441   0.041299  -6.670 3.74e-11 ***
